"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[9373],{8407(e,t,n){n.r(t),n.d(t,{assets:()=>h,contentTitle:()=>a,default:()=>c,frontMatter:()=>s,metadata:()=>r,toc:()=>l});var o=n(4848),i=n(8453);const s={},a=void 0,r={id:"GameVictory/\u7b2c\u4e09\u7ae0_\u5fae\u8edf\u7684\u6050\u61fc\u8207 Xbox \u7684\u8a95\u751f",title:"\u7b2c\u4e09\u7ae0_\u5fae\u8edf\u7684\u6050\u61fc\u8207 Xbox \u7684\u8a95\u751f",description:"Chapter 3: Microsoft's Fear and the Birth of Xbox",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/GameVictory/\u7b2c\u4e09\u7ae0_\u5fae\u8edf\u7684\u6050\u61fc\u8207 Xbox \u7684\u8a95\u751f.md",sourceDirName:"GameVictory",slug:"/GameVictory/\u7b2c\u4e09\u7ae0_\u5fae\u8edf\u7684\u6050\u61fc\u8207 Xbox \u7684\u8a95\u751f",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u4e09\u7ae0_\u5fae\u8edf\u7684\u6050\u61fc\u8207 Xbox \u7684\u8a95\u751f",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Chapter 2: Microsoft's Trojan Horse \u2014 DirectX",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u4e8c\u7ae0_\u7279\u6d1b\u4f0a\u6728\u99ac_v3"},next:{title:"Chapter 4: Sega's Five-Million-Dollar Mercy",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u56db\u7ae0_\u4e16\u5609\u7684\u4e94\u767e\u842c\u7f8e\u5143\u5584\u6b3e_v1"}},h={},l=[{value:"Chapter 3: Microsoft&#39;s Fear and the Birth of Xbox",id:"chapter-3-microsofts-fear-and-the-birth-of-xbox",level:2},{value:"I. Motive for the Crime",id:"i-motive-for-the-crime",level:3},{value:"II. Forging the Weapon",id:"ii-forging-the-weapon",level:3},{value:"III. Defense",id:"iii-defense",level:3},{value:"IV. Closing Arguments",id:"iv-closing-arguments",level:3},{value:"V. The Loot is Still Being Divided",id:"v-the-loot-is-still-being-divided",level:3}];function d(e){const t={em:"em",h2:"h2",h3:"h3",hr:"hr",img:"img",p:"p",strong:"strong",...(0,i.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(t.h2,{id:"chapter-3-microsofts-fear-and-the-birth-of-xbox",children:"Chapter 3: Microsoft's Fear and the Birth of Xbox"}),"\n",(0,o.jsx)(t.p,{children:"In January 2024, Microsoft announced the layoff of 1,900 people from its gaming division. Three months earlier, it had just spent $69 billion to complete the largest acquisition in the history of human commerce\u2014Activision Blizzard. In the spring of the same year, several Xbox exclusive games quietly appeared on the PlayStation 5 store. By autumn, Phil Spencer\u2014the last spokesperson of the Xbox brand trusted by gamers\u2014handed over the reins."}),"\n",(0,o.jsx)(t.p,{children:"A young game developer stared at the news, feeling something was off. You spend the most money in the world to buy the largest game publisher in the world, and then you send its games to your competitor's console? Your entire hardware team is laid off, your studios close one by one, and your exclusivity strategy exists in name only\u2014is this a pivot, or a suicide?"}),"\n",(0,o.jsx)(t.p,{children:"Seamus Blackley\u2014the co-creator of the original Xbox in 2001\u2014offered a phrase on social media: palliative care."}),"\n",(0,o.jsx)(t.p,{children:"A console, from birth to palliative care, walked for twenty-three years."}),"\n",(0,o.jsxs)(t.p,{children:["But if you go back to the day it was born, you will find\u2014its fate was decided the moment it was created. Because Xbox was never born to win the console war. ",(0,o.jsx)(t.strong,{children:"It was born so Microsoft wouldn't lose another war."})]}),"\n",(0,o.jsx)(t.hr,{}),"\n",(0,o.jsx)(t.h3,{id:"i-motive-for-the-crime",children:"I. Motive for the Crime"}),"\n",(0,o.jsx)(t.p,{children:"In March 1999, Sony held a press conference in Tokyo. Ken Kutaragi stepped onto the stage and showed the world the core of the PlayStation 2: a chip called the Emotion Engine."}),"\n",(0,o.jsx)(t.p,{children:'Ken Kutaragi was not a man of low profile. He didn\'t call the PS2 a "game console." He called it "the home computer of the twenty-first century." His slides contained charts, computing power comparisons, and a side-by-side floating-point performance comparison between the PS2 and a workstation CPU. His subtext was completely unsubtle: the computing power of this console had already touched the territory of low-end PCs. He hinted that the PS2 would one day be able to browse the internet, act as a DVD player, and even run operating systems.'}),"\n",(0,o.jsx)(t.p,{children:"Two years later, Sony actually did release a Linux kit specifically for the PS2, complete with a keyboard, mouse, and hard drive. It didn't run very well. But that wasn't important."}),"\n",(0,o.jsx)(t.p,{children:"What was important was the panic that press conference triggered in Redmond."}),"\n",(0,o.jsx)(t.p,{children:"Gates' concern touched the exact same nerve as his fear five years earlier when DOS games couldn't run: the entry point. The previous entry point was the desktop PC\u2014young people played games on it, and when they grew up, they continued using Windows in the office. This time, the entry point was the living room. If the box under every family's TV was a PlayStation instead of a Windows PC; if Sony turned the PS2 into a home terminal that could browse the internet, process documents, and send and receive emails\u2014the moat of Windows in the consumer market would start leaking from the living room side."}),"\n",(0,o.jsx)(t.p,{children:'Gates convened a high-level meeting. In the version that later leaked out, he asked a very Gates-esque question: "What do we have that can stop this?"'}),"\n",(0,o.jsx)(t.p,{children:"The answer was nothing. Microsoft had no console, no home hardware, and no game development studios. It had absolutely no presence in the consumer's living room."}),"\n",(0,o.jsx)(t.p,{children:"So he made a decision\u2014build one."}),"\n",(0,o.jsx)(t.hr,{}),"\n",(0,o.jsx)(t.h3,{id:"ii-forging-the-weapon",children:"II. Forging the Weapon"}),"\n",(0,o.jsxs)(t.p,{children:["Before this matter even surfaced on Gates' desk, four people inside Microsoft were already secretly building a prototype. Seamus Blackley was the most technically proficient among them\u2014he had previously developed a game called ",(0,o.jsx)(t.em,{children:"Trespasser"})," at Looking Glass Studios. When that game's physics engine ran on consumer-grade PCs in 1998, it was so severely ahead of its time regarding hardware capabilities that it resulted in a commercial disaster. Blackley learned one thing from that experience: ",(0,o.jsx)(t.strong,{children:"The computing power a game needs will always be more than what the current consumer hardware can provide."})]}),"\n",(0,o.jsx)(t.p,{children:"The prototype proposal he and his colleagues came up with had an extremely straightforward name: DirectX Box."}),"\n",(0,o.jsxs)(t.p,{children:["The name gave everything away. This was not a game console\u2014this was a machine that ripped DirectX out of the PC and stuffed it under the television. Its CPU was from Intel, its GPU was from NVIDIA, its core operating system was a stripped-down version of Windows 2000, and its development tools were simply Visual Studio plus the DirectX SDK. Microsoft didn't even plan to design its own chips, nor did it plan to invent a new API. What it set out to do was precise to the point of cruelty: ",(0,o.jsx)(t.strong,{children:"Take the exact toolset PC game developers already knew, and move it intact into the living room."})]}),"\n",(0,o.jsx)(t.p,{children:"Only those who have read Chapter 2 can truly appreciate the brilliance of this strategy."}),"\n",(0,o.jsx)(t.p,{children:"Microsoft had spent five years using DirectX to lock the entire PC game development ecosystem onto Windows. By 1999, the engine of every mainstream PC game studio on the market was written in Direct3D, their toolchains were Windows-based, and their engineers had grown up using Visual C++. Writing games for Windows was as natural as breathing to them."}),"\n",(0,o.jsxs)(t.p,{children:["The genius of the Xbox was this: It wasn't asking these developers to learn anything new. ",(0,o.jsx)(t.strong,{children:"It was just copying the building they already lived in and placing it in the living room."})]}),"\n",(0,o.jsx)(t.p,{children:"For developers, making games for the Xbox came at almost zero cost\u2014the same API, the same IDE, the same shader language. Change a few lines of code, and your PC game runs on the Xbox. This \"almost free cross-platform\" capability was something neither Sony nor Nintendo could offer. The PS2's Emotion Engine architecture was exceptionally bizarre, and its development difficulty was notorious at the time; Nintendo's GameCube was an entirely closed-off world."}),"\n",(0,o.jsx)(t.p,{children:(0,o.jsx)(t.strong,{children:"But this design also exposed the Xbox's most fatal structural problem\u2014its hardware cost was calculated based on the price of PC components."})}),"\n",(0,o.jsx)(t.p,{children:"When Sony and Nintendo built consoles, they used highly customized chips, meaning the marginal cost after mass production was extremely low. Microsoft used Intel's Pentium III and NVIDIA's custom GPU\u2014both were publicly traded companies, both had their own gross margin requirements, and neither could possibly slash their profits for Microsoft's console dream. The result: For every Xbox sold, Microsoft lost over $100. Throughout the lifespan of the first-generation Xbox, Microsoft's hardware losses conservatively exceeded $4 billion."}),"\n",(0,o.jsxs)(t.p,{children:["That number was astronomical in the gaming industry at the time. But to Microsoft, $4 billion was not a gaming investment\u2014",(0,o.jsx)(t.strong,{children:"it was an insurance premium."})," It insured the living room flank of Windows. As long as the PS2 failed to become the standard for home computers, the consumer entry point for Windows was safe. As for whether the Xbox itself made money, it didn't matter."]}),"\n",(0,o.jsx)(t.p,{children:"Gates approved this insurance policy."}),"\n",(0,o.jsx)(t.hr,{}),"\n",(0,o.jsx)(t.h3,{id:"iii-defense",children:"III. Defense"}),"\n",(0,o.jsx)(t.p,{children:"On November 15, 2001, the Xbox launched in North America."}),"\n",(0,o.jsx)(t.p,{children:'Gates himself attended the midnight launch event\u2014a man worth tens of billions of dollars, standing at the door of Toys "R" Us in New York\'s Times Square, personally handing the first Xbox to consumers waiting in line. The image was broadcast by media worldwide. But most reporters on the scene didn\'t realize one thing: what they were witnessing was not a software company "entering the gaming industry," but the opening ceremony of an operating system defense war.'}),"\n",(0,o.jsxs)(t.p,{children:["When the Xbox launched, the blockbuster title accompanying it was ",(0,o.jsx)(t.em,{children:"Halo: Combat Evolved"}),". The studio behind it, Bungie, had originally been making it as a Mac game\u2014Apple's Steve Jobs had even personally demonstrated an early version of ",(0,o.jsx)(t.em,{children:"Halo"})," at Macworld in 1999. Microsoft outright bought Bungie, turning ",(0,o.jsx)(t.em,{children:"Halo"})," from a Mac exclusive into an Xbox exclusive."]}),"\n",(0,o.jsxs)(t.p,{children:["The logic of this acquisition perfectly matched the logic of the entire Xbox: It wasn't about making a good game; it was about ensuring the competitor's platform didn't have a good game. Every step Microsoft took in the console market carried the DNA of a defender\u2014",(0,o.jsx)(t.strong,{children:"I don't need to win; I just need you to not win too much."})]}),"\n",(0,o.jsx)(t.p,{children:"But the DNA of a defender also means one thing: the day the threat disappears is the day the weapon loses its reason to exist."}),"\n",(0,o.jsx)(t.hr,{}),"\n",(0,o.jsx)(t.h3,{id:"iv-closing-arguments",children:"IV. Closing Arguments"}),"\n",(0,o.jsx)(t.p,{children:"The PS2 ultimately sold over 155 million units, making it the best-selling game console in history. Ken Kutaragi's \"home computer\" dream never materialized\u2014the PS2's Linux kit sold fewer than 100,000 units, and the vast majority of buyers only used the console to play games and watch DVDs."}),"\n",(0,o.jsx)(t.p,{children:"Microsoft's fear, in retrospect, was overestimated. The PS2 never truly threatened Windows. What truly replaced the home PC was not the living room console, but the smartphone in everyone's pocket a decade later\u2014but that is another story."}),"\n",(0,o.jsx)(t.p,{children:"However, the Xbox had already been built. The $4 billion had already been spent. An entire gaming division had already been established."}),"\n",(0,o.jsx)(t.p,{children:"What do you do with a weapon forged for defense?"}),"\n",(0,o.jsx)(t.p,{children:'Microsoft chose a seemingly logical path: since they had already invested so much money, they might as well do it seriously. The Xbox 360 launched in 2005 and finally started turning a profit in certain quarters. The Xbox One launched in 2013, its market share crushed by the PS4, but the Game Pass subscription model showed Wall Street "recurring revenue." By 2023, Microsoft spent $69 billion to buy Activision Blizzard\u2014the largest acquisition in the history of human gaming.'}),"\n",(0,o.jsx)(t.p,{children:"On the surface, this path looked like a success story that kept growing bigger."}),"\n",(0,o.jsx)(t.p,{children:'But deep down, the DNA of the Xbox had never changed since day one. It was a wall, not a city. The function of a wall is to keep invaders out; the function of a city is to allow the people inside to prosper. Microsoft never managed the Xbox as a city that needed its residents (players) to flourish\u2014every major decision it made started from the perspective of "what the Windows empire needs."'}),"\n",(0,o.jsx)(t.p,{children:"So when Satya Nadella made a judgment in 2023\u2014that AI was the next battlefield needing insurance, and the living room was long obsolete\u2014the fate of the Xbox was flipped in that exact moment. Activision games bought for $69 billion were released on PlayStation. Exclusive games were opened up one by one. The hardware team suffered layoffs. Studios were closed."}),"\n",(0,o.jsxs)(t.p,{children:["This wasn't suicide. ",(0,o.jsx)(t.strong,{children:"This was a wall being torn down, its bricks moved to build another wall."})]}),"\n",(0,o.jsx)(t.p,{children:"The new wall Nadella was building was called AI infrastructure. The AI capital expenditure Microsoft announced in 2024 exceeded $80 billion. Where did this money come from? Part of the answer: it was squeezed out of a gaming division that no longer required loss-making subsidies."}),"\n",(0,o.jsx)(t.p,{children:"Here, the pattern identified in Chapter 2 reappears\u2014only this time, its direction is reversed."}),"\n",(0,o.jsxs)(t.p,{children:["DirectX's pattern was offensive: ",(0,o.jsx)(t.strong,{children:"Use convenience to attract developers, lock in the ecosystem, and finally lock in the consumers."})," The Xbox's pattern was defensive: ",(0,o.jsx)(t.strong,{children:"Use losses to block the flank, use time to drain the opponent's ambition, and then when the threat subsides, dismantle the fortifications and reallocate resources to the next battlefield."})]}),"\n",(0,o.jsx)(t.p,{children:"Both patterns share the exact same underlying assumption: gaming is not the end goal; gaming is the means. Players are not customers; players are bargaining chips."}),"\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"When a company treats gaming as a means rather than an end, it will never sacrifice its own strategic interests for the interests of the players."})," This principle will reach its final settlement in Chapter 10\u2014how Microsoft ultimately disposed of the debris of the Xbox."]}),"\n",(0,o.jsx)(t.hr,{}),"\n",(0,o.jsx)(t.h3,{id:"v-the-loot-is-still-being-divided",children:"V. The Loot is Still Being Divided"}),"\n",(0,o.jsx)(t.p,{children:"Back to the young developer staring at the news in 2024."}),"\n",(0,o.jsx)(t.p,{children:"He felt Microsoft's actions were irrational, because he understood the Xbox as a game console. A game console company spending $69 billion to buy a game studio, only to give those games to its rival\u2014of course that's irrational."}),"\n",(0,o.jsx)(t.p,{children:'But if he understood the Xbox as a wall, everything would make sense. When a wall is no longer needed, you tear it down and move the bricks to a useful place. As for the people living behind the wall\u2014the players who bought an Xbox, subscribed to Game Pass, and trusted the "exclusive" promises\u2014their investments were never on Microsoft\'s balance sheet.'}),"\n",(0,o.jsx)(t.p,{children:"This bill has not yet been settled. When Microsoft moved the Xbox's bricks to build AI infrastructure, it simultaneously tore down something else\u2014Chapter 8 will explain how important this is\u2014which is the console as a long-term, stable source of orders for advanced process chips. The SoCs for both the PS5 and Xbox Series X were produced by TSMC on a 7nm node, with contracts lasting seven to ten years. These kinds of orders are one of the ballast stones that give TSMC the courage to invest in next-generation nodes. If the console market shrinks, this ballast stone will loosen."}),"\n",(0,o.jsx)(t.p,{children:"But that is for later."}),"\n",(0,o.jsx)(t.p,{children:"What we need to talk about now is the GPU inside the Xbox chassis. It was made by NVIDIA\u2014a custom chip based on the GeForce 3 architecture, codenamed NV2A. By 2001, NVIDIA was already the overlord of the PC graphics card market."}),"\n",(0,o.jsx)(t.p,{children:"But five years earlier\u2014in 1996\u2014NVIDIA nearly died over a contract."}),"\n",(0,o.jsx)(t.p,{children:"The client for that contract was a Japanese company. It, too, was fighting a console war it was destined to lose, with the money in its pockets dwindling by the day. According to the logic of all business textbooks, it should have saved every last cent for itself."}),"\n",(0,o.jsx)(t.p,{children:"It didn't. It paid its final $5 million to a young man who had made a fatal mistake."}),"\n",(0,o.jsx)(t.p,{children:"That company was Sega. That young man was Jensen Huang."}),"\n",(0,o.jsx)(t.p,{children:(0,o.jsx)(t.img,{src:n(3110).A+"",width:"1200",height:"655"})})]})}function c(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},3110(e,t,n){n.d(t,{A:()=>o});const o=n.p+"assets/images/ch03_en 1-5e6b3dca4cfbde557c815645cb70430f.png"},8453(e,t,n){n.d(t,{R:()=>a,x:()=>r});var o=n(6540);const i={},s=o.createContext(i);function a(e){const t=o.useContext(s);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:a(e.components),o.createElement(s.Provider,{value:t},e.children)}}}]);